import{_ as a,o as r,c as t,a4 as o}from"./chunks/framework.EG5hAXdg.js";const h=JSON.parse('{"title":"About support","description":"This page gives on overview of user support in HUNT Cloud.","frontmatter":{"title":"About support","category":"HUNT Cloud","permalink":"/administer-science/start-here/support","outline":0,"description":"This page gives on overview of user support in HUNT Cloud."},"headers":[],"relativePath":"administer-science/start-here/support.md","filePath":"administer-science/start-here/support.md"}'),i={name:"administer-science/start-here/support.md"};function s(n,e,c,u,l,d){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="about-support" tabindex="-1">About support <a class="header-anchor" href="#about-support" aria-label="Permalink to &quot;About support&quot;">​</a></h1><p><strong>We are here to help your science flow.</strong></p><nav class="table-of-contents"><ul><li><a href="#service-desk">Service desk</a></li><li><a href="#chat">Chat</a></li><li><a href="#account-program">Account program</a></li><li><a href="#tingweek">Tingweek</a></li><li><a href="#read-more">Read more</a></li></ul></nav><p>It&#39;s fun to do science, and it&#39;s frustrating when you get stuck on your way. HUNT Cloud provides support for different levels of our community to ensure scientific flow.</p><h3 id="service-desk" tabindex="-1">Service desk <a class="header-anchor" href="#service-desk" aria-label="Permalink to &quot;Service desk&quot;">​</a></h3><p>This is our go to place for updates to your lab. Our service desks provide predefined orders that go directly to the correct person on our side, and such usually ensures quick responses.</p><h3 id="chat" tabindex="-1">Chat <a class="header-anchor" href="#chat" aria-label="Permalink to &quot;Chat&quot;">​</a></h3><p>All lab users gets invited to Slack. Each lab gets their own lab channel where you can reach both our technical and administrative teams here at HUNT Cloud for quick responses. In addition, all users gets invited to a joint community channel where we communicate running updates, including response communication during service disruptions.</p><h3 id="account-program" tabindex="-1">Account program <a class="header-anchor" href="#account-program" aria-label="Permalink to &quot;Account program&quot;">​</a></h3><p>We have a dedicated account program for follow-up of larger research groups, centers and departments. This support focus on strategic growth, data and expertise activation, digital lab management and similar.</p><h3 id="tingweek" tabindex="-1">Tingweek <a class="header-anchor" href="#tingweek" aria-label="Permalink to &quot;Tingweek&quot;">​</a></h3><p>We appoint time three times per year to meet for information, feedback and discussion on how to develop the services in HUNT Cloud forward. We call these user forums for Tings. Invitations are forwarded on email.</p><p>We encourage all users to join and voice their opinions in the four Tings: &quot;Lab ting&quot; focus on user experience inside labs, &quot;Administrator ting&quot; focus on administrative aspects, &quot;Data controller ting&quot; focus on ethics, privacy and security aspects, and finally the &quot;Financial ting&quot; focuses on financial and strategic aspects of our development.</p><h3 id="read-more" tabindex="-1">Read more <a class="header-anchor" href="#read-more" aria-label="Permalink to &quot;Read more&quot;">​</a></h3><ul><li><a href="/do-science/service-desk/">Do science service desk</a> for lab users.</li><li><a href="/administer-science/service-desk/">Administer science service desk</a> for lab administrators.</li><li><a href="/govern-science/tingweek/">HUNT Cloud Tingweeks</a></li></ul>',15)])])}const m=a(i,[["render",s]]);export{h as __pageData,m as default};
